    // ── Activity handlers ───────────────────────────────────

    async fn handle_activity_list(&self, params: Value) -> WsFrame {
        let store = match self.task_store().await {
            Ok(s) => s,
            Err(f) => return f,
        };
        let agent_id = params.get("agent_id").and_then(|v| v.as_str());
        let event_type = params.get("type").and_then(|v| v.as_str());
        let limit = params.get("limit").and_then(|v| v.as_i64()).unwrap_or(20);
        let offset = params.get("offset").and_then(|v| v.as_i64()).unwrap_or(0);

        match store.list_activity(agent_id, event_type, limit, offset).await {
            Ok((rows, total)) => {
                let events: Vec<Value> = rows.iter().map(|r| activity_row_to_json(r)).collect();
                WsFrame::ok_response("", json!({ "events": events, "total": total }))
            }
            Err(e) => WsFrame::error_response("", &format!("list activity: {e}")),
        }
    }

    // ── Work Timeline (G11) ─────────────────────────────────
    //
    // Company-level Gantt rows derived from the stores that already carry
    // real timestamps: the task board (ranged: created/claimed → completed),
    // the activity feed (instants), and the in-memory heartbeat scheduler
    // (`last_run` instants only — heartbeat run durations are NOT persisted
    // anywhere, so heartbeats are honestly rendered as dots, never bars).

    async fn handle_timeline_list(&self, params: Value) -> WsFrame {
        let store = match self.task_store().await {
            Ok(s) => s,
            Err(f) => return f,
        };
        let now = Utc::now();
        let to = params
            .get("to")
            .and_then(|v| v.as_str())
            .and_then(parse_timeline_ts)
            .unwrap_or(now);
        let from = params
            .get("from")
            .and_then(|v| v.as_str())
            .and_then(parse_timeline_ts)
            .unwrap_or_else(|| to - chrono::Duration::hours(24));
        if from >= to {
            return WsFrame::error_response("", "invalid range: `from` must be earlier than `to`");
        }
        let agent_id = params
            .get("agent_id")
            .and_then(|v| v.as_str())
            .filter(|s| !s.is_empty());

        let tasks = match store.list_tasks(None, agent_id, None).await {
            Ok(t) => t,
            Err(e) => return WsFrame::error_response("", &format!("timeline tasks: {e}")),
        };
        // Most-recent TIMELINE_ROW_CAP activity events; events older than the
        // newest cap-full may be missing from wide windows — the `truncated`
        // flag + `cap` in the response make that visible to the client.
        let (activities, _total) = match store
            .list_activity(agent_id, None, TIMELINE_ROW_CAP as i64, 0)
            .await
        {
            Ok(r) => r,
            Err(e) => return WsFrame::error_response("", &format!("timeline activity: {e}")),
        };
        let heartbeats: Vec<(String, Option<String>)> = {
            let hb = self.heartbeat.read().await;
            match hb.as_ref() {
                Some(scheduler) => scheduler
                    .status()
                    .await
                    .into_iter()
                    .filter(|h| agent_id.is_none_or(|a| a == h.agent_id))
                    .map(|h| (h.agent_id, h.last_run))
                    .collect(),
                None => Vec::new(),
            }
        };

        let (rows, truncated) = derive_timeline_rows(&tasks, &activities, &heartbeats, from, to, now);
        WsFrame::ok_response(
            "",
            json!({
                "rows": rows,
                "cap": TIMELINE_ROW_CAP,
                "truncated": truncated,
                "from": from.to_rfc3339(),
                "to": to.to_rfc3339(),
            }),
        )
    }

    // ── Run inspector (G12) ─────────────────────────────────
    //
    // A "run" is one user turn → the next assistant turn of the same session
    // in `sessions.db` (the only place per-run conversation turns are
    // persisted). Tool events come from the MCP tool audit trail
    // (`tool_calls.jsonl`), correlated by agent + time window.
    //
    // HONESTY NOTE (what per-run event persistence actually is): session
    // text turns come from sessions.db, MCP-tool-call receipts from
    // tool_calls.jsonl, and — since the G12 upgrade — CLI-native tool steps
    // (`StepTracker` Start boundaries) plus `TodoWrite` board snapshots from
    // the bounded `run_steps.db` (written best-effort on the channel-reply
    // fresh-spawn CLI path; PTY-pool sessions and thinking summaries are
    // still NOT captured). `runs.get` states the remaining limits in its
    // response instead of fabricating events.

    async fn handle_runs_list(&self, params: Value) -> WsFrame {
        let agent_filter = params
            .get("agent_id")
            .and_then(|v| v.as_str())
            .unwrap_or("")
            .to_string();
        if !agent_filter.is_empty() && !is_valid_agent_id(&agent_filter) {
            return WsFrame::error_response("", "Invalid agent_id format");
        }
        let limit = params
            .get("limit")
            .and_then(|v| v.as_u64())
            .unwrap_or(RUNS_LIST_DEFAULT_LIMIT as u64)
            .min(RUNS_LIST_MAX_LIMIT as u64) as usize;

        let db_path = self.home_dir.join("sessions.db");
        if !db_path.exists() {
            return WsFrame::ok_response("", json!({ "runs": [] }));
        }
        let conn = match rusqlite::Connection::open(&db_path) {
            Ok(c) => c,
            Err(e) => return WsFrame::error_response("", &format!("open sessions db: {e}")),
        };

        let mut rows = match query_run_msg_rows(&conn, &agent_filter, RUNS_SCAN_MSG_CAP) {
            Ok(r) => r,
            Err(e) => return WsFrame::error_response("", &format!("runs query: {e}")),
        };
        // Fold expects per-session chronological order.
        rows.sort_by(|a, b| (&a.session_id, a.rowid).cmp(&(&b.session_id, b.rowid)));
        let now = Utc::now();
        let mut runs = fold_session_runs(&rows, now);
        runs.sort_by(|a, b| b.started_at.cmp(&a.started_at));
        runs.truncate(limit);

        // Step counts: prefer the persisted CLI-native step stream
        // (run_steps.db — real `tool_use` boundaries, matched by session key
        // + window). Runs predating the step store (or PTY-pool runs, which
        // don't stream through the fresh-spawn parser) have no rows there
        // and fall back to the MCP tool audit trail as before. The two are
        // never summed — MCP calls also appear as CLI tool_use boundaries,
        // so adding them would double-count.
        let tool_rows = load_tool_call_rows(&self.home_dir);
        let step_metas = crate::run_steps::shared_store(&self.home_dir)
            .and_then(|s| s.recent_tool_step_meta(&agent_filter, RUN_STEPS_SCAN_CAP).ok())
            .unwrap_or_default();
        let runs_json: Vec<Value> = runs
            .iter()
            .map(|r| {
                let native = step_metas
                    .iter()
                    .filter(|(sk, ts)| step_meta_in_run_window(sk, ts, r, now))
                    .count();
                let steps = if native > 0 {
                    native
                } else {
                    tool_rows
                        .iter()
                        .filter(|t| tool_row_in_run_window(t, r, now))
                        .count()
                };
                run_summary_to_json(r, steps)
            })
            .collect();
        WsFrame::ok_response("", json!({ "runs": runs_json }))
    }

    async fn handle_runs_get(&self, params: Value, ctx: &UserContext) -> WsFrame {
        let run_id = params.get("run_id").and_then(|v| v.as_str()).unwrap_or("");
        let Some((session_id, rowid_str)) = run_id.rsplit_once('#') else {
            return WsFrame::error_response("", "Missing or invalid 'run_id' parameter");
        };
        let Ok(rowid) = rowid_str.parse::<i64>() else {
            return WsFrame::error_response("", "Missing or invalid 'run_id' parameter");
        };

        let db_path = self.home_dir.join("sessions.db");
        if !db_path.exists() {
            return WsFrame::error_response("", "Run not found");
        }
        let conn = match rusqlite::Connection::open(&db_path) {
            Ok(c) => c,
            Err(e) => return WsFrame::error_response("", &format!("open sessions db: {e}")),
        };

        // Resolve the run's user turn + owning agent. Fail closed: an unknown
        // run id yields "not found" BEFORE any payload is exposed.
        //
        // 2026-07 MED: honour the /undo //rollback tombstones like runs.list
        // does (`query_run_msg_rows`) — runs.get is the user-facing transcript
        // view, not an audit surface, so undone turns must not resolve.
        // Pre-migration DBs (no hidden/undone_at columns) fall back to the
        // plain query, mirroring `query_run_msg_rows`.
        let head_row = |row: &rusqlite::Row<'_>| {
            Ok((
                row.get::<_, String>(0)?,
                row.get::<_, String>(1)?,
                row.get::<_, String>(2)?,
                row.get::<_, String>(3)?,
            ))
        };
        let head = conn
            .query_row(
                "SELECT s.agent_id, m.role, m.content, m.timestamp
                 FROM session_messages m JOIN sessions s ON s.id = m.session_id
                 WHERE m.id = ?1 AND m.session_id = ?2
                   AND COALESCE(m.hidden, 0) = 0 AND m.undone_at IS NULL",
                params![rowid, session_id],
                head_row,
            )
            .or_else(|e| match e {
                // Older DB without the tombstone columns → plain query.
                rusqlite::Error::SqliteFailure(..) => conn.query_row(
                    "SELECT s.agent_id, m.role, m.content, m.timestamp
                     FROM session_messages m JOIN sessions s ON s.id = m.session_id
                     WHERE m.id = ?1 AND m.session_id = ?2",
                    params![rowid, session_id],
                    head_row,
                ),
                other => Err(other),
            });
        let (agent_id, role, user_content, started_at) = match head {
            Ok(v) => v,
            Err(_) => return WsFrame::error_response("", "Run not found"),
        };
        if role != "user" {
            return WsFrame::error_response("", "Run not found");
        }
        // Agent-scoped authz — same intent as activity.list, resolved from
        // the run's owning agent (viewer level, fail-closed for non-admins).
        if !ctx.is_admin() {
            if let Err(e) = acl::require_agent_access(ctx, &agent_id, AccessLevel::Viewer) {
                return WsFrame::error_response("", &e);
            }
        }

        // Window boundaries: the next user turn bounds this run; the first
        // assistant turn inside the bound is the reply.
        let next_user: Option<(i64, String)> = conn
            .query_row(
                "SELECT id, timestamp FROM session_messages
                 WHERE session_id = ?1 AND id > ?2 AND role = 'user'
                   AND COALESCE(hidden, 0) = 0 AND undone_at IS NULL
                 ORDER BY id LIMIT 1",
                params![session_id, rowid],
                |row| Ok((row.get::<_, i64>(0)?, row.get::<_, String>(1)?)),
            )
            .or_else(|e| match e {
                rusqlite::Error::SqliteFailure(..) => conn.query_row(
                    "SELECT id, timestamp FROM session_messages
                     WHERE session_id = ?1 AND id > ?2 AND role = 'user'
                     ORDER BY id LIMIT 1",
                    params![session_id, rowid],
                    |row| Ok((row.get::<_, i64>(0)?, row.get::<_, String>(1)?)),
                ),
                other => Err(other),
            })
            .ok();
        let bound_id = next_user.as_ref().map(|(id, _)| *id).unwrap_or(i64::MAX);
        let assistant: Option<(String, String)> = conn
            .query_row(
                "SELECT content, timestamp FROM session_messages
                 WHERE session_id = ?1 AND id > ?2 AND id < ?3 AND role = 'assistant'
                   AND COALESCE(hidden, 0) = 0 AND undone_at IS NULL
                 ORDER BY id LIMIT 1",
                params![session_id, rowid, bound_id],
                |row| Ok((row.get::<_, String>(0)?, row.get::<_, String>(1)?)),
            )
            .or_else(|e| match e {
                rusqlite::Error::SqliteFailure(..) => conn.query_row(
                    "SELECT content, timestamp FROM session_messages
                     WHERE session_id = ?1 AND id > ?2 AND id < ?3 AND role = 'assistant'
                     ORDER BY id LIMIT 1",
                    params![session_id, rowid, bound_id],
                    |row| Ok((row.get::<_, String>(0)?, row.get::<_, String>(1)?)),
                ),
                other => Err(other),
            })
            .ok();

        let now = Utc::now();
        let (status, ended_at) = match &assistant {
            Some((_, ts)) => ("completed".to_string(), Some(ts.clone())),
            None => {
                if next_user.is_some() {
                    ("no_reply".to_string(), None)
                } else {
                    (run_open_status(&started_at, now), None)
                }
            }
        };

        // Tool events (MCP audit trail) inside the run window.
        let window_end: Option<chrono::DateTime<Utc>> = match &ended_at {
            Some(ts) => parse_timeline_ts(ts),
            None => match &next_user {
                Some((_, ts)) => parse_timeline_ts(ts),
                None => {
                    if status == "running" {
                        Some(now)
                    } else {
                        parse_timeline_ts(&started_at)
                            .map(|t| t + chrono::Duration::seconds(RUN_RUNNING_WINDOW_SECS))
                    }
                }
            },
        };
        let window_start = parse_timeline_ts(&started_at);

        let mut events: Vec<Value> = Vec::new();
        events.push(json!({
            "kind": "text",
            "role": "user",
            "ts": started_at,
            "preview": duduclaw_core::truncate_chars(&user_content, RUN_TEXT_PREVIEW_CHARS),
        }));
        if let (Some(ws), Some(we)) = (window_start, window_end) {
            for t in load_tool_call_rows(&self.home_dir) {
                if t.agent_id != agent_id {
                    continue;
                }
                let Some(ts) = parse_timeline_ts(&t.ts) else { continue };
                if ts >= ws && ts <= we {
                    events.push(json!({
                        "kind": "tool_use",
                        "tool": t.tool,
                        "ok": t.ok,
                        "ts": t.ts,
                        "preview": duduclaw_core::truncate_chars(&t.preview, RUN_TOOL_PREVIEW_CHARS),
                    }));
                }
            }
        }
        // Persisted CLI-native step events (run_steps.db) inside the window:
        // tool_step Start boundaries + todo_update board snapshots. Matched
        // by session key (exact) + agent + time window; a missing/empty
        // store simply contributes nothing (older runs stay as they were).
        if let (Some(ws), Some(we)) = (window_start, window_end) {
            if let Some(store) = crate::run_steps::shared_store(&self.home_dir) {
                if let Ok(rows) = store.recent_for_session(session_id, RUN_STEPS_SESSION_CAP) {
                    events.extend(persisted_step_events_for_window(&rows, ws, we));
                }
            }
        }
        if let Some((content, ts)) = &assistant {
            events.push(json!({
                "kind": "text",
                "role": "assistant",
                "ts": ts,
                "preview": duduclaw_core::truncate_chars(content, RUN_TEXT_PREVIEW_CHARS),
            }));
        }
        // Chronological order. Compare by the PARSED instant, not the raw
        // string — sources format the same time differently (sessions.db uses
        // `+00:00`, run_steps uses `Z`), so a raw string compare mis-orders
        // same-instant cross-source events. `seq` breaks remaining ties
        // (monotonic within the run_steps stream); a stable sort then keeps
        // insertion order (user turn first) for events with neither signal.
        let ts_instant = |v: &serde_json::Value| -> Option<chrono::DateTime<chrono::Utc>> {
            v.get("ts")
                .and_then(|t| t.as_str())
                .and_then(|s| chrono::DateTime::parse_from_rfc3339(s).ok())
                .map(|dt| dt.with_timezone(&chrono::Utc))
        };
        events.sort_by(|a, b| {
            let ia = ts_instant(a);
            let ib = ts_instant(b);
            ia.cmp(&ib).then_with(|| {
                let sa = a.get("seq").and_then(|v| v.as_i64());
                let sb = b.get("seq").and_then(|v| v.as_i64());
                sa.cmp(&sb)
            })
        });

        let run = json!({
            "id": run_id,
            "session_id": session_id,
            "agent_id": agent_id,
            "channel": run_channel_of(session_id),
            "started_at": started_at,
            "ended_at": ended_at,
            "status": status,
        });
        WsFrame::ok_response(
            "",
            json!({
                "run": run,
                "events": events,
                // Honest provenance: which store produced which event kind,
                // and which live-stream kinds are NOT persisted anywhere.
                // Thinking summaries are still only counted (never captured)
                // by the stream parser, so they remain unpersisted.
                "event_sources": {
                    "text": "sessions.db",
                    "tool_use": "tool_calls.jsonl (MCP audit)",
                    "tool_step": "run_steps.db",
                    "todo_update": "run_steps.db",
                },
                "not_persisted": ["thinking_summaries"],
            }),
        )
    }

    // ── WebChat session history + resume handlers (WP3) ─────────
    //
    // These back the dashboard's "past conversations" picker and resume flow.
    // Sessions are keyed by agent in `sessions.db`; listing/history are
    // read-only and agent-scoped (same fail-closed intent as `runs.*`). The
    // resume write path itself lives in `webchat.rs` (the `/ws/chat` socket);
    // these RPCs only surface what exists so the client can pick a session id
    // to resume.

    async fn handle_chat_sessions_list(&self, params: Value) -> WsFrame {
        let agent_filter = params
            .get("agent_id")
            .and_then(|v| v.as_str())
            .map(str::trim)
            .filter(|s| !s.is_empty());
        if let Some(a) = agent_filter {
            if !is_valid_agent_id(a) {
                return WsFrame::error_response("", "Invalid agent_id format");
            }
        }
        let limit = params
            .get("limit")
            .and_then(|v| v.as_u64())
            .unwrap_or(CHAT_SESSIONS_LIST_DEFAULT_LIMIT as u64)
            .min(CHAT_SESSIONS_LIST_MAX_LIMIT as u64) as usize;

        let rc = match self.reply_ctx.read().await.clone() {
            Some(c) => c,
            // Reply context not yet wired (very early startup) — no sessions to
            // show. Empty is the honest answer, not an error.
            None => return WsFrame::ok_response("", json!({ "sessions": [] })),
        };

        match rc.session_manager.list_sessions(agent_filter, limit).await {
            Ok(list) => {
                let sessions: Vec<Value> = list
                    .iter()
                    .map(|s| {
                        json!({
                            "session_id": s.id,
                            "agent_id": s.agent_id,
                            "title": s.title,
                            "last_active": s.last_active,
                            "turns": s.turn_count,
                            "tokens": s.total_tokens,
                            "lineage": s.lineage,
                        })
                    })
                    .collect();
                WsFrame::ok_response("", json!({ "sessions": sessions }))
            }
            Err(e) => WsFrame::error_response("", &format!("list sessions: {e}")),
        }
    }

    async fn handle_chat_sessions_history(&self, params: Value, ctx: &UserContext) -> WsFrame {
        let session_id = params
            .get("session_id")
            .and_then(|v| v.as_str())
            .unwrap_or("")
            .trim()
            .to_string();
        if session_id.is_empty() {
            return WsFrame::error_response("", "session_id is required");
        }
        let limit = params
            .get("limit")
            .and_then(|v| v.as_u64())
            .unwrap_or(CHAT_HISTORY_DEFAULT_LIMIT as u64)
            .min(CHAT_HISTORY_MAX_LIMIT as u64) as usize;

        let rc = match self.reply_ctx.read().await.clone() {
            Some(c) => c,
            None => return WsFrame::error_response("", "session store unavailable"),
        };

        // Resolve the owning agent; fail closed on an unknown id (never expose
        // an empty transcript for a session that does not exist).
        let owner = match rc.session_manager.session_agent(&session_id).await {
            Ok(Some(a)) => a,
            Ok(None) => return WsFrame::error_response("", "session not found"),
            Err(e) => return WsFrame::error_response("", &format!("resolve session: {e}")),
        };
        // Agent-scoped authz — viewer level, fail-closed for non-admins (mirrors
        // runs.get). Prevents loading a conversation for an agent the caller
        // cannot see.
        if !ctx.is_admin() {
            if let Err(e) = acl::require_agent_access(ctx, &owner, AccessLevel::Viewer) {
                return WsFrame::error_response("", &e);
            }
        }

        match rc.session_manager.get_messages(&session_id).await {
            Ok(msgs) => {
                // F9: `get_messages` returns oldest→newest. Show the NEWEST
                // `limit` turns (where the user left off), not the oldest — on a
                // long resumed conversation the oldest window is stale scrollback.
                // Skip to the tail while preserving chronological order.
                let start = msgs.len().saturating_sub(limit);
                let messages: Vec<Value> = msgs
                    .iter()
                    .skip(start)
                    .map(|m| {
                        json!({
                            "role": m.role,
                            // CJK-safe cap — long single turns are bounded so the
                            // payload stays sane; normal messages pass through whole.
                            "content": duduclaw_core::truncate_chars(&m.content, CHAT_HISTORY_MSG_MAX_CHARS),
                            "timestamp": m.timestamp,
                            "tokens": m.tokens,
                        })
                    })
                    .collect();
                WsFrame::ok_response(
                    "",
                    json!({
                        "session_id": session_id,
                        "agent_id": owner,
                        "messages": messages,
                    }),
                )
            }
            Err(e) => WsFrame::error_response("", &format!("session history: {e}")),
        }
    }

    // ── Live Run Forking handlers (RFC-26) ──────────────────
    //
    // Forks execute in the MCP-server process and persist to the cross-process
    // `ForkStore` (`<home>/fork_store.db`); the dashboard reads it here.

    fn open_fork_store(&self) -> Result<duduclaw_fork::ForkStore, WsFrame> {
        let path = self.home_dir.join("fork_store.db");
        if !path.exists() {
            return Err(WsFrame::error_response("", "no forks yet (fork store not created)"));
        }
        duduclaw_fork::ForkStore::open(&path)
            .map_err(|e| WsFrame::error_response("", &format!("open fork store: {e}")))
    }

    fn handle_fork_list(&self, params: Value) -> WsFrame {
        // No fork has ever been created yet → the store file doesn't exist.
        // That's an empty list, not an error: return [] so the dashboard shows
        // its "no forks yet" empty state instead of a scary error banner.
        if !self.home_dir.join("fork_store.db").exists() {
            return WsFrame::ok_response("", json!({ "forks": [] }));
        }
        let store = match self.open_fork_store() {
            Ok(s) => s,
            Err(f) => return f,
        };
        let limit = params.get("limit").and_then(|v| v.as_u64()).unwrap_or(50).min(500) as usize;
        match store.list_forks(limit) {
            Ok(forks) => {
                let rows: Vec<Value> = forks
                    .iter()
                    .map(|f| {
                        json!({
                            "fork_id": f.fork_id,
                            "agent_id": f.agent_id,
                            "merge_mode": f.merge_mode,
                            "resolved": f.resolved,
                            "winner": f.winner,
                            "promoted": f.promoted,
                            "aggregate_spent_usd": f.aggregate_spent_usd,
                            "created_at": f.created_at,
                        })
                    })
                    .collect();
                WsFrame::ok_response("", json!({ "forks": rows }))
            }
            Err(e) => WsFrame::error_response("", &format!("list forks: {e}")),
        }
    }

    fn handle_fork_inspect(&self, params: Value) -> WsFrame {
        let store = match self.open_fork_store() {
            Ok(s) => s,
            Err(f) => return f,
        };
        let fork_id = match params.get("fork_id").and_then(|v| v.as_str()) {
            Some(f) => f,
            None => return WsFrame::error_response("", "fork_id is required"),
        };
        let fork = match store.get_fork(fork_id) {
            Ok(Some(f)) => f,
            Ok(None) => return WsFrame::error_response("", "fork not found"),
            Err(e) => return WsFrame::error_response("", &format!("get fork: {e}")),
        };
        let branches = store.list_branches(fork_id).unwrap_or_default();
        let branch_json: Vec<Value> = branches
            .iter()
            .map(|b| {
                json!({
                    "branch_id": b.branch_id,
                    "steering": b.steering,
                    "state": b.state,
                    "budget_usd": b.budget_usd,
                    "spent_usd": b.spent_usd,
                    "test_exit_code": b.test_exit_code,
                    "output": duduclaw_core::truncate_bytes(&b.output, 8000),
                })
            })
            .collect();
        WsFrame::ok_response("", json!({
            "fork_id": fork.fork_id,
            "agent_id": fork.agent_id,
            "prompt": duduclaw_core::truncate_bytes(&fork.prompt, 4000),
            "merge_mode": fork.merge_mode,
            "resolved": fork.resolved,
            "winner": fork.winner,
            "promoted": fork.promoted,
            "branches": branch_json,
        }))
    }

    fn handle_fork_resolve(&self, params: Value) -> WsFrame {
        let store = match self.open_fork_store() {
            Ok(s) => s,
            Err(f) => return f,
        };
        let fork_id = match params.get("fork_id").and_then(|v| v.as_str()) {
            Some(f) => f,
            None => return WsFrame::error_response("", "fork_id is required"),
        };
        let branch_id = match params.get("branch_id").and_then(|v| v.as_str()) {
            Some(b) => b,
            None => return WsFrame::error_response("", "branch_id is required"),
        };
        let fork = match store.get_fork(fork_id) {
            Ok(Some(f)) => f,
            Ok(None) => return WsFrame::error_response("", "fork not found"),
            Err(e) => return WsFrame::error_response("", &format!("get fork: {e}")),
        };
        if fork.resolved {
            return WsFrame::error_response("", "fork already resolved");
        }
        let branches = store.list_branches(fork_id).unwrap_or_default();
        if !branches.iter().any(|b| b.branch_id == branch_id) {
            return WsFrame::error_response("", "branch not found in fork");
        }
        let aggregate = branches.iter().map(|b| b.spent_usd).sum();
        match store.set_resolution(fork_id, Some(branch_id), true, true, aggregate) {
            Ok(_) => WsFrame::ok_response("", json!({
                "fork_id": fork_id, "resolved": true, "winner": branch_id,
            })),
            Err(e) => WsFrame::error_response("", &format!("resolve fork: {e}")),
        }
    }

    // ── Migrate-from handlers ───────────────────────────────

    /// `migrate.scan` — dry-run migration plan. Spawns `current_exe
    /// migrate-from <platform> --json [--source <abs>]`, 60s timeout, returns
    /// the parsed JSON verbatim. Fail-closed: any spawn/timeout/parse failure
    /// is an error frame carrying the reason — never fabricated data.
    async fn handle_migrate_scan(&self, params: Value) -> WsFrame {
        self.run_migrate_cli(params, false).await
    }

    /// `migrate.apply` — actually write the imported data. Same as scan plus
    /// `--apply` (and `--rename` when `rename=true`), with a 300s timeout.
    async fn handle_migrate_apply(&self, params: Value) -> WsFrame {
        self.run_migrate_cli(params, true).await
    }

    /// Shared driver for both migrate RPCs: validate params, build the argv,
    /// spawn this binary, enforce a timeout, and parse the single stdout JSON.
    async fn run_migrate_cli(&self, params: Value, apply: bool) -> WsFrame {
        let platform = match params.get("platform").and_then(|v| v.as_str()) {
            Some(p) if migrate_platform_allowed(p) => p.to_string(),
            Some(p) => {
                return WsFrame::error_response(
                    "",
                    &format!("unsupported platform '{p}' (expected openclaw/hermes/paperclip)"),
                );
            }
            None => return WsFrame::error_response("", "platform is required"),
        };

        // Optional source: when given it MUST be an absolute path (a relative
        // path would resolve against the gateway's cwd, which is ambiguous).
        let source = params.get("source").and_then(|v| v.as_str());
        if let Err(e) = validate_migrate_source(source) {
            return WsFrame::error_response("", &e);
        }
        let rename = apply && params.get("rename").and_then(|v| v.as_bool()).unwrap_or(false);

        let exe = match std::env::current_exe() {
            Ok(p) => p,
            Err(e) => {
                return WsFrame::error_response("", &format!("cannot locate self binary: {e}"));
            }
        };

        let mut cmd = tokio::process::Command::new(&exe);
        cmd.arg("migrate-from").arg(&platform).arg("--json");
        if let Some(src) = source {
            cmd.arg("--source").arg(src);
        }
        if apply {
            cmd.arg("--apply");
        }
        if rename {
            cmd.arg("--rename");
        }
        // Pin DUDUCLAW_HOME to the gateway's home so a launchd-spawned gateway
        // (which may not inherit the interactive env) migrates into the right
        // tree rather than a default `~/.duduclaw`.
        cmd.env("DUDUCLAW_HOME", &self.home_dir);
        cmd.stdout(std::process::Stdio::piped());
        cmd.stderr(std::process::Stdio::piped());

        let dur = if apply {
            std::time::Duration::from_secs(300)
        } else {
            std::time::Duration::from_secs(60)
        };
        let output = match tokio::time::timeout(dur, cmd.output()).await {
            Ok(Ok(out)) => out,
            Ok(Err(e)) => {
                return WsFrame::error_response("", &format!("spawn migrate-from failed: {e}"));
            }
            Err(_) => {
                return WsFrame::error_response(
                    "",
                    &format!("migrate-from timed out after {}s", dur.as_secs()),
                );
            }
        };

        if !output.status.success() {
            // Non-zero exit = fatal (bad args, paperclip w/o source, ...).
            // Surface a trimmed stderr tail so the operator sees the cause.
            let stderr = String::from_utf8_lossy(&output.stderr);
            let tail = duduclaw_core::truncate_bytes(stderr.trim(), 500);
            let msg = if tail.is_empty() {
                format!("migrate-from exited with status {}", output.status)
            } else {
                format!("migrate-from failed: {tail}")
            };
            return WsFrame::error_response("", &msg);
        }

        // stdout must be exactly one JSON object.
        let stdout = String::from_utf8_lossy(&output.stdout);
        match serde_json::from_str::<Value>(stdout.trim()) {
            Ok(v) => WsFrame::ok_response("", v),
            Err(e) => WsFrame::error_response(
                "",
                &format!("could not parse migrate-from JSON output: {e}"),
            ),
        }
    }

    // ── Autopilot handlers ──────────────────────────────────

    /// WP14-T14.7: list pending approvals for the approval center. Optional
    /// `agent_id` filter. Read-only; opens approvals.db per call.
    async fn handle_approvals_list(&self, params: Value) -> WsFrame {
        let agent_filter = params.get("agent_id").and_then(|v| v.as_str());
        let broker = match crate::approval::ApprovalBroker::open(&self.home_dir) {
            Ok(b) => b,
            Err(e) => return WsFrame::error_response("", &format!("open approvals: {e}")),
        };
        match broker.list_pending(agent_filter).await {
            Ok(rows) => {
                let items: Vec<Value> = rows
                    .iter()
                    .map(|r| {
                        let kind = crate::governance::ApprovalKind::parse(&r.action_kind);
                        json!({
                            "id": r.id.as_str(),
                            "agent_id": r.agent_id,
                            "kind": kind.as_str(),
                            "summary": r.summary,
                            "payload": r.payload,
                            "created_at": r.created_at,
                            "ttl_seconds": r.ttl_seconds,
                        })
                    })
                    .collect();
                WsFrame::ok_response("", json!({ "approvals": items, "count": items.len() }))
            }
            Err(e) => WsFrame::error_response("", &format!("list approvals: {e}")),
        }
    }

    /// WP14-T14.7: decide a pending approval from the dashboard ("就地同意/退回").
    /// Board-only kinds (WP17 StrategicPlan/AgentHire) require admin — the
    /// dashboard's fail-closed stand-in for board rights until a board-user model
    /// lands. Records `dashboard:<user_id>` as the decider for audit.
    async fn handle_approvals_decide(&self, params: Value, ctx: &UserContext) -> WsFrame {
        let id = match params.get("id").and_then(|v| v.as_str()) {
            Some(s) if !s.is_empty() => s.to_string(),
            _ => return WsFrame::error_response("", "id is required"),
        };
        let approve = params.get("approve").and_then(|v| v.as_bool()).unwrap_or(false);
        let reason = params.get("reason").and_then(|v| v.as_str()).unwrap_or("").to_string();
        let broker = match crate::approval::ApprovalBroker::open(&self.home_dir) {
            Ok(b) => b,
            Err(e) => return WsFrame::error_response("", &format!("open approvals: {e}")),
        };
        let approval_id = crate::approval::ApprovalId::from(id.clone());
        // Snapshot the record BEFORE deciding — we need its action_kind +
        // payload to run any post-decision side-effect (e.g. skill_create).
        let record = broker.get(&approval_id).await.ok().flatten();
        // Board-kind gate (WP17 invariant).
        if let Some(rec) = &record {
            let kind = crate::governance::ApprovalKind::parse(&rec.action_kind);
            if kind.requires_board() && !ctx.is_admin() {
                return WsFrame::error_response(
                    "",
                    "this approval kind requires board (admin) rights to decide",
                );
            }
        }
        let decided_by = format!("dashboard:{}", ctx.user_id);
        if let Err(e) = broker.decide(&approval_id, approve, &decided_by).await {
            return WsFrame::error_response("", &format!("decide: {e}"));
        }

        // ── S1 (PORTICO): mint an epoch-bound capability on approve ──
        // Approving is no longer a permanent grant. If the approval payload
        // carries a `scope_epoch` (a task_id / session_id subgoal key), mint
        // a revocable capability handle bound to it; closing that subgoal
        // (task done / session end) auto-revokes the handle. Absent a
        // scope_epoch we skip minting — the legacy one-shot behaviour — so
        // this is additive and never blocks existing approve flows.
        let mut capability_handle: Value = Value::Null;
        if approve {
            if let Some(rec) = &record {
                if let Some(epoch) = rec.payload.get("scope_epoch").and_then(|v| v.as_str()) {
                    if !epoch.is_empty() {
                        match crate::capability::CapabilityBroker::open(&self.home_dir) {
                            Ok(caps) => {
                                let ttl = rec
                                    .payload
                                    .get("capability_ttl_seconds")
                                    .and_then(|v| v.as_i64())
                                    .unwrap_or(rec.ttl_seconds);
                                match caps
                                    .grant_from_approval(&broker, &approval_id, epoch, ttl, None)
                                    .await
                                {
                                    Ok(g) => capability_handle = json!(g.handle_id),
                                    Err(e) => {
                                        // Fail-closed: minting failed ⇒ report,
                                        // do NOT silently proceed as if granted.
                                        return WsFrame::error_response(
                                            "",
                                            &format!("已核准但核發授權憑證失敗（保守拒絕）：{e}"),
                                        );
                                    }
                                }
                            }
                            Err(e) => {
                                return WsFrame::error_response(
                                    "",
                                    &format!("開啟授權憑證儲存失敗：{e}"),
                                );
                            }
                        }
                    }
                }
            }
        }

        // ── Side-effect: custom skill creation (V13-T13.0) ──
        // Approver identity is already gated by require_manager!; routing to a
        // human's manager is a fallback here (no manager_id column yet ⇒ any
        // admin/manager may approve; single-admin self-approval is audited).
        let mut side_effect: Value = Value::Null;
        if let Some(rec) = &record {
            if rec.action_kind == crate::custom_skills::ACTION_KIND_SKILL_CREATE {
                if approve {
                    match self.install_approved_custom_skill(&id, rec, &ctx.user_id).await {
                        Ok(name) => {
                            let created_by = rec
                                .payload
                                .get("created_by_user")
                                .and_then(|v| v.as_str())
                                .unwrap_or("");
                            side_effect = json!({
                                "installed_skill": name,
                                "self_approved": crate::custom_skills::is_self_approval(created_by, &ctx.user_id),
                            });
                        }
                        Err(e) => {
                            return WsFrame::error_response(
                                "",
                                &format!("approved, but install side-effect failed: {e}"),
                            );
                        }
                    }
                } else {
                    // Deny → mark the registry row rejected with the reason.
                    if let Some(cs_id) = rec.payload.get("custom_skill_id").and_then(|v| v.as_str()) {
                        if let Ok(store) = self.custom_skill_store() {
                            let _ = store
                                .transition(
                                    cs_id,
                                    crate::custom_skills::CustomSkillStatus::Rejected,
                                    None,
                                    Some(if reason.is_empty() { "rejected by approver" } else { &reason }),
                                    false,
                                )
                                .await;
                        }
                        side_effect = json!({ "custom_skill_rejected": cs_id });
                    }
                }
            }
        }

        WsFrame::ok_response("", json!({
            "id": id,
            "decided": if approve { "approved" } else { "denied" },
            "side_effect": side_effect,
            "capability_handle": capability_handle,
        }))
    }

    /// WP14-T14.6: recent budget-breaker incidents from `budget_events.jsonl`,
    /// newest first, plus a per-agent open-count. `limit` default 50.
    async fn handle_budget_incidents(&self, params: Value) -> WsFrame {
        let limit = params.get("limit").and_then(|v| v.as_u64()).unwrap_or(50) as usize;
        let path = self.home_dir.join("budget_events.jsonl");
        let raw = std::fs::read_to_string(&path).unwrap_or_default();
        let mut events: Vec<Value> = raw
            .lines()
            .filter(|l| !l.trim().is_empty())
            .filter_map(|l| serde_json::from_str::<Value>(l).ok())
            .collect();
        events.reverse(); // newest first
        let mut per_agent: std::collections::HashMap<String, u64> = std::collections::HashMap::new();
        for e in &events {
            if let Some(a) = e.get("agent_id").and_then(|v| v.as_str()) {
                *per_agent.entry(a.to_string()).or_insert(0) += 1;
            }
        }
        let recent: Vec<Value> = events.into_iter().take(limit).collect();
        let agents: Vec<Value> = per_agent
            .into_iter()
            .map(|(agent_id, count)| json!({ "agent_id": agent_id, "open_events": count }))
            .collect();
        WsFrame::ok_response("", json!({ "incidents": recent, "by_agent": agents }))
    }

    /// WP10-T10.1: skill leaderboard ranked by estimated minutes saved. Scans
    /// global + per-agent skills, reads `estimated_minutes_saved` from metadata.
    /// Only skills carrying an estimate (i.e. approved via WP8's flow) appear —
    /// drafts have no estimate and are naturally excluded (no fabricated data).
    async fn handle_skills_leaderboard(&self, params: Value) -> WsFrame {
        let limit = params.get("limit").and_then(|v| v.as_u64()).unwrap_or(20) as usize;
        let loc = duduclaw_agent::skill_loader::DEFAULT_SKILL_LOCALE;

        // Build the (dir, scope, owner) scan list, then await each.
        let mut targets: Vec<(std::path::PathBuf, &'static str, String)> =
            vec![(self.home_dir.join("skills"), "global", String::new())];
        if let Ok(rd) = std::fs::read_dir(self.home_dir.join("agents")) {
            for entry in rd.flatten() {
                if entry.path().is_dir() {
                    let agent = entry.file_name().to_string_lossy().to_string();
                    targets.push((entry.path().join("SKILLS"), "agent", agent));
                }
            }
        }

        let mut rows: Vec<Value> = Vec::new();
        for (dir, scope, owner) in targets {
            for sk in duduclaw_agent::registry::AgentRegistry::load_skills(&dir).await {
                let meta = duduclaw_agent::skill_loader::parse_skill_meta_from_content(
                    &sk.content, &sk.name,
                );
                if let Some(mins) = meta.estimated_minutes_saved {
                    rows.push(json!({
                        "skill": sk.name,
                        "display_name": meta.display_name(loc),
                        "estimated_minutes_saved": mins,
                        "scope": scope,
                        "owner": owner,
                    }));
                }
            }
        }

        rows.sort_by(|a, b| {
            b["estimated_minutes_saved"].as_u64().unwrap_or(0)
                .cmp(&a["estimated_minutes_saved"].as_u64().unwrap_or(0))
        });
        rows.truncate(limit);
        WsFrame::ok_response("", json!({
            "leaderboard": rows,
            "metric": "estimated_minutes_saved",
            "note": "Ranked by per-use minutes saved; usage-count multiplication pending a persisted counter.",
        }))
    }

    // ── Growth / gamification (V10-T10.0) ───────────────────

    /// Gather the real, already-persisted facts the growth engine scores. Every
    /// value comes from an existing internal surface (tasks store / wiki /
    /// skills registry / cron / custom-skill registry); nothing is fabricated.
    /// Missing/uninjected surfaces contribute 0 rather than an error so the
    /// snapshot degrades gracefully.
    async fn gather_growth_facts(&self) -> crate::growth::GrowthFacts {
        // Agents.
        let agents_count = self.registry.read().await.list().len() as u64;

        // Completed tasks (status == "done", NOT "completed").
        let tasks_completed = match self.task_store.read().await.as_ref().cloned() {
            Some(store) => store
                .list_tasks(Some("done"), None, None)
                .await
                .map(|v| v.len() as u64)
                .unwrap_or(0),
            None => 0,
        };

        // Knowledge pages: every agent wiki + the shared wiki.
        let mut knowledge_pages: u64 = 0;
        if let Ok(rd) = std::fs::read_dir(self.home_dir.join("agents")) {
            for entry in rd.flatten() {
                let wiki_dir = entry.path().join("wiki");
                if wiki_dir.exists() {
                    let store = duduclaw_memory::WikiStore::new(wiki_dir);
                    if let Ok(pages) = store.list_pages() {
                        knowledge_pages += pages.len() as u64;
                    }
                }
            }
        }
        if self.home_dir.join("shared").join("wiki").exists() {
            let store = duduclaw_memory::WikiStore::new_shared(&self.home_dir);
            if let Ok(pages) = store.list_pages() {
                knowledge_pages += pages.len() as u64;
            }
        }

        // Installed skills: global + each agent's SKILLS.
        let mut skills_acquired: u64 =
            duduclaw_agent::registry::AgentRegistry::load_skills(&self.home_dir.join("skills"))
                .await
                .len() as u64;
        if let Ok(rd) = std::fs::read_dir(self.home_dir.join("agents")) {
            for entry in rd.flatten() {
                if entry.path().is_dir() {
                    let dir = entry.path().join("SKILLS");
                    skills_acquired +=
                        duduclaw_agent::registry::AgentRegistry::load_skills(&dir).await.len()
                            as u64;
                }
            }
        }

        // Successful routine runs = total runs − failures (real cron counters).
        let routines_completed = match self.cron_store.read().await.as_ref().cloned() {
            Some(store) => store
                .list_all()
                .await
                .map(|rows| {
                    rows.iter()
                        .map(|r| (r.run_count - r.failure_count).max(0) as u64)
                        .sum()
                })
                .unwrap_or(0),
            None => 0,
        };

        // Approved custom skills — count + cumulative real saved-hours (floored).
        // Both derive from one registry read so the numbers can't disagree.
        let (custom_skills_approved, custom_skill_saved_hours) =
            match crate::custom_skills::CustomSkillStore::open(&self.home_dir) {
                Ok(store) => {
                    let approved = store.list_approved().await.unwrap_or_default();
                    let now = chrono::Utc::now();
                    let saved: f64 = approved
                        .iter()
                        .map(|r| crate::custom_skills::estimate_saved_hours(r, now))
                        .sum();
                    (approved.len() as u64, saved.floor().max(0.0) as u64)
                }
                Err(_) => (0, 0),
            };

        crate::growth::GrowthFacts {
            agents_count,
            tasks_completed,
            knowledge_pages,
            skills_acquired,
            routines_completed,
            custom_skills_approved,
            // Filled by `handle_growth_snapshot` (needs the growth store to record
            // today's snapshot first); 0 here for callers that don't (daily_report).
            inbox_zero_streak_days: 0,
            custom_skill_saved_hours,
        }
    }

    /// Count the actionable inbox for the current moment — the server's own view
    /// of "work waiting on a human": pending approvals + blocked tasks + open
    /// budget incidents. Drives the `inbox_zero_streak_7` achievement. Any source
    /// that fails to open contributes 0 (a store we can't read is not fabricated
    /// as work).
    async fn count_actionable_inbox(&self) -> u64 {
        let pending = match crate::approval::ApprovalBroker::open(&self.home_dir) {
            Ok(b) => b.list_pending(None).await.map(|v| v.len() as u64).unwrap_or(0),
            Err(_) => 0,
        };
        let blocked = match self.task_store.read().await.as_ref().cloned() {
            Some(store) => store
                .list_tasks(Some("blocked"), None, None)
                .await
                .map(|v| v.len() as u64)
                .unwrap_or(0),
            None => 0,
        };
        let incidents = std::fs::read_to_string(self.home_dir.join("budget_events.jsonl"))
            .map(|raw| raw.lines().filter(|l| !l.trim().is_empty()).count() as u64)
            .unwrap_or(0);
        pending.saturating_add(blocked).saturating_add(incidents)
    }

    /// `growth.snapshot` — company XP/level + the achievement wall (progress,
    /// availability, unlock timestamps). Login-readable; the judging engine is
    /// pure and every scored value is a real fact.
    async fn handle_growth_snapshot(&self) -> WsFrame {
        let store = match crate::growth::GrowthStore::open(&self.home_dir) {
            Ok(s) => s,
            Err(e) => return WsFrame::error_response("", &format!("open growth store: {e}")),
        };
        // L5 §14: lazily record today's actionable-inbox count (server self-check),
        // then read the current zero-streak. `record_inbox_snapshot` takes the
        // daily MIN, so an inbox cleared at any point today counts as zero.
        let now = chrono::Utc::now();
        let today = now.format("%Y-%m-%d").to_string();
        let actionable = self.count_actionable_inbox().await;
        let _ = store
            .record_inbox_snapshot(&today, actionable as i64, &now.to_rfc3339())
            .await;
        let inbox_streak = store.inbox_zero_streak_days().await.unwrap_or(0);

        let mut facts = self.gather_growth_facts().await;
        facts.inbox_zero_streak_days = inbox_streak;
        let (snap, unlock_times) = match crate::growth::snapshot_with_store(&store, &facts).await {
            Ok(v) => v,
            Err(e) => return WsFrame::error_response("", &format!("growth snapshot: {e}")),
        };
        let achievements: Vec<Value> = snap
            .achievements
            .iter()
            .map(|a| {
                json!({
                    "id": a.id,
                    "unlocked": a.unlocked,
                    "progress_current": a.progress_current,
                    "progress_denominator": a.progress_denominator,
                    "xp_reward": a.xp_reward,
                    "available": a.available,
                    "unavailable_reason": a.unavailable_reason,
                    "unlocked_at": unlock_times.get(&a.id),
                })
            })
            .collect();
        WsFrame::ok_response("", json!({
            "xp": snap.xp,
            "level": snap.level,
            "xp_into_level": snap.xp_into_level,
            "xp_for_next_level": snap.xp_for_next_level,
            "facts": facts,
            "achievements": achievements,
        }))
    }

    /// `growth.daily_report` — yesterday's settlement card: completed tasks,
    /// cost, most-active agent, new knowledge pages, and the XP gained. Cached
    /// per date in `growth.db`. `date` param (YYYY-MM-DD) overrides "yesterday".
    async fn handle_growth_daily_report(&self, params: Value) -> WsFrame {
        let store = match crate::growth::GrowthStore::open(&self.home_dir) {
            Ok(s) => s,
            Err(e) => return WsFrame::error_response("", &format!("open growth store: {e}")),
        };
        let report_date = params
            .get("date")
            .and_then(|v| v.as_str())
            .map(|s| s.to_string())
            .unwrap_or_else(|| {
                (chrono::Utc::now() - chrono::Duration::days(1))
                    .format("%Y-%m-%d")
                    .to_string()
            });

        // Serve from cache when present (a settled past day never changes).
        if let Ok(Some(cached)) = store.get_daily_report(&report_date).await {
            if let Ok(v) = serde_json::from_str::<Value>(&cached) {
                return WsFrame::ok_response("", v);
            }
        }

        // Completed tasks whose completed_at falls on report_date.
        let (tasks_done_yesterday, most_active_agent) =
            match self.task_store.read().await.as_ref().cloned() {
                Some(ts) => {
                    let done = ts.list_tasks(Some("done"), None, None).await.unwrap_or_default();
                    let count = done
                        .iter()
                        .filter(|t| {
                            t.completed_at
                                .as_deref()
                                .map(|c| c.starts_with(&report_date))
                                .unwrap_or(false)
                        })
                        .count() as u64;
                    // Most active agent = most task completions on report_date.
                    let mut by_agent: std::collections::HashMap<String, u64> =
                        std::collections::HashMap::new();
                    for t in &done {
                        if t.completed_at
                            .as_deref()
                            .map(|c| c.starts_with(&report_date))
                            .unwrap_or(false)
                            && !t.assigned_to.is_empty()
                        {
                            *by_agent.entry(t.assigned_to.clone()).or_insert(0) += 1;
                        }
                    }
                    let top = by_agent
                        .into_iter()
                        .max_by_key(|(_, c)| *c)
                        .map(|(a, _)| a);
                    (count, top)
                }
                None => (0, None),
            };

        // New knowledge pages authored on report_date (agent + shared wikis).
        let mut new_knowledge_yesterday: u64 = 0;
        let count_pages_on = |dir: duduclaw_memory::WikiStore| -> u64 {
            dir.list_pages()
                .map(|pages| {
                    pages
                        .iter()
                        .filter(|p| p.updated.format("%Y-%m-%d").to_string() == report_date)
                        .count() as u64
                })
                .unwrap_or(0)
        };
        if let Ok(rd) = std::fs::read_dir(self.home_dir.join("agents")) {
            for entry in rd.flatten() {
                let wiki_dir = entry.path().join("wiki");
                if wiki_dir.exists() {
                    new_knowledge_yesterday += count_pages_on(duduclaw_memory::WikiStore::new(wiki_dir));
                }
            }
        }
        if self.home_dir.join("shared").join("wiki").exists() {
            new_knowledge_yesterday +=
                count_pages_on(duduclaw_memory::WikiStore::new_shared(&self.home_dir));
        }

        // Cost over report_date (rolling 24h telemetry approximation, in cents).
        let cost_cents = if let Some(t) = crate::cost_telemetry::get_telemetry() {
            t.summary_global(24).await.map(|s| s.total_cost_millicents).unwrap_or(0)
        } else {
            0
        };

        // XP earned yesterday from the datable events we can attribute (task
        // completions + new knowledge pages). Skills/routines lack a per-day
        // timestamp here, so they are intentionally excluded — documented,
        // not fabricated.
        let xp_gained = tasks_done_yesterday * crate::growth::XP_PER_TASK
            + new_knowledge_yesterday * crate::growth::XP_PER_KNOWLEDGE_PAGE;

        let payload = json!({
            "date": report_date,
            "tasks_completed": tasks_done_yesterday,
            "cost_cents": cost_cents,
            "most_active_agent": most_active_agent,
            "new_knowledge_pages": new_knowledge_yesterday,
            "xp_gained": xp_gained,
            "xp_basis": "task completions ×12 + new knowledge pages ×8 (skills/routines excluded — no per-day timestamp)",
        });

        // Cache only past days (today may still change).
        let today = chrono::Utc::now().format("%Y-%m-%d").to_string();
        if report_date != today {
            let now = chrono::Utc::now().to_rfc3339();
            let _ = store
                .put_daily_report(&report_date, &payload.to_string(), &now)
                .await;
        }

        WsFrame::ok_response("", payload)
    }

    async fn handle_autopilot_list(&self) -> WsFrame {
        let store = match self.ap_store().await {
            Ok(s) => s,
            Err(f) => return f,
        };
        match store.list_rules().await {
            Ok(rows) => {
                let rules: Vec<Value> = rows.iter().map(|r| autopilot_rule_to_json(r)).collect();
                WsFrame::ok_response("", json!({ "rules": rules }))
            }
            Err(e) => WsFrame::error_response("", &format!("list autopilot: {e}")),
        }
    }

    async fn handle_autopilot_create(&self, params: Value) -> WsFrame {
        let store = match self.ap_store().await {
            Ok(s) => s,
            Err(f) => return f,
        };
        let name = params.get("name").and_then(|v| v.as_str()).unwrap_or("").to_string();
        if name.is_empty() {
            return WsFrame::error_response("", "name is required");
        }
        let trigger_event = params.get("trigger_event").and_then(|v| v.as_str()).unwrap_or("task_created").to_string();
        if let Err(e) = validate_autopilot_trigger_event(&trigger_event) {
            return WsFrame::error_response("", &e);
        }
        let conditions = params.get("conditions").cloned().unwrap_or(json!({}));
        let action = params.get("action").cloned().unwrap_or(json!({}));
        // Reject malformed rules at write time so the dashboard surfaces
        // the error immediately rather than silently in autopilot_history
        // the first time the rule would have fired.
        if let Err(e) = validate_autopilot_action(&action) {
            return WsFrame::error_response("", &e);
        }

        let row = AutopilotRuleRow {
            id: uuid::Uuid::new_v4().to_string(),
            name,
            enabled: true,
            trigger_event,
            conditions: conditions.to_string(),
            action: action.to_string(),
            created_at: Utc::now().to_rfc3339(),
            last_triggered_at: None,
            trigger_count: 0,
        };
        if let Err(e) = store.insert_rule(&row).await {
            return WsFrame::error_response("", &format!("create autopilot rule: {e}"));
        }
        WsFrame::ok_response("", json!({ "rule": autopilot_rule_to_json(&row) }))
    }

    async fn handle_autopilot_update(&self, params: Value) -> WsFrame {
        let store = match self.ap_store().await {
            Ok(s) => s,
            Err(f) => return f,
        };
        let rule_id = params.get("rule_id").and_then(|v| v.as_str()).unwrap_or("");
        if rule_id.is_empty() {
            return WsFrame::error_response("", "rule_id is required");
        }
        // Re-validate any provided trigger_event / action fields.
        if let Some(t) = params.get("trigger_event").and_then(|v| v.as_str()) {
            if let Err(e) = validate_autopilot_trigger_event(t) {
                return WsFrame::error_response("", &e);
            }
        }
        if let Some(a) = params.get("action") {
            if let Err(e) = validate_autopilot_action(a) {
                return WsFrame::error_response("", &e);
            }
        }
        match store.update_rule(rule_id, &params).await {
            Ok(Some(row)) => WsFrame::ok_response("", json!({ "rule": autopilot_rule_to_json(&row) })),
            Ok(None) => WsFrame::error_response("", &format!("Rule not found: {rule_id}")),
            Err(e) => WsFrame::error_response("", &format!("update rule: {e}")),
        }
    }

    async fn handle_autopilot_remove(&self, params: Value) -> WsFrame {
        let store = match self.ap_store().await {
            Ok(s) => s,
            Err(f) => return f,
        };
        let rule_id = params.get("rule_id").and_then(|v| v.as_str()).unwrap_or("");
        if rule_id.is_empty() {
            return WsFrame::error_response("", "rule_id is required");
        }
        match store.remove_rule(rule_id).await {
            Ok(true) => WsFrame::ok_response("", json!({ "success": true })),
            Ok(false) => WsFrame::error_response("", &format!("Rule not found: {rule_id}")),
            Err(e) => WsFrame::error_response("", &format!("remove rule: {e}")),
        }
    }

    async fn handle_autopilot_history(&self, params: Value) -> WsFrame {
        let store = match self.ap_store().await {
            Ok(s) => s,
            Err(f) => return f,
        };
        let rule_id = params.get("rule_id").and_then(|v| v.as_str());
        let limit = params.get("limit").and_then(|v| v.as_i64()).unwrap_or(20);
        match store.list_history(rule_id, limit).await {
            Ok(entries) => {
                let result: Vec<Value> = entries
                    .iter()
                    .map(|e| {
                        json!({
                            "id": e.id,
                            "rule_id": e.rule_id,
                            "rule_name": e.rule_name,
                            "triggered_at": e.triggered_at,
                            "result": e.result,
                            "details": e.details,
                        })
                    })
                    .collect();
                WsFrame::ok_response("", json!({ "entries": result }))
            }
            Err(e) => WsFrame::error_response("", &format!("autopilot history: {e}")),
        }
    }

